from pygments.lexer import RegexLexer
from pygments.token import Comment, Operator, Keyword, Name, String, \
    Number, Punctuation, Whitespace

__all__ = ['BQNLexer']


class BQNLexer(RegexLexer):
    """
    A simple BQN lexer.
    """
    name = 'BQN'
    url = 'https://mlochbaum.github.io/BQN/index.html'
    aliases = ['bqn']
    filenames = ['*.bqn']
    mimetypes = []
    version_added = '2.16'

    # An inter_word_char. Necessary because \w matches all alphanumeric
    # Unicode characters, including ones (e.g., рқ•Ҡ) that BQN treats special.
    _iwc = r'((?=[^рқ•Һрқ•Ҹрқ”Ҫрқ”ҫрқ•Ҡрқ•Ёрқ•©рқ•—рқ•ҳрқ•Өрқ•Ј])\w)'

    tokens = {
        'root': [
            # Whitespace
            # ==========
            (r'\s+', Whitespace),
            #
            # Comment
            # =======
            # '#' is a comment that continues to the end of the line
            (r'#.*$', Comment.Single),
            #
            # Strings
            # =======
            (r'\'((\'\')|[^\'])*\'', String.Single),
            (r'"(("")|[^"])*"', String.Double),
            #
            # Null Character
            # ==============
            # Literal representation of the null character
            (r'@', String.Symbol),
            #
            # Punctuation
            # ===========
            # This token type is used for diamond, commas
            # and  array and list brackets and strand syntax
            (r'[\.вӢ„,\[\]вҹЁвҹ©вҖҝ]', Punctuation),
            #
            # Expression Grouping
            # ===================
            # Since this token type is important in BQN, it is not included in
            # the punctuation token type but rather in the following one
            (r'[\(\)]', String.Regex),
            #
            # Numbers
            # =======
            # Includes the numeric literals and the Nothing character
            (r'ВҜ?[0-9](([0-9]|_)*\.?([0-9]|_)+|([0-9]|_)*)([Ee][ВҜ]?([0-9]|_)+)?|ВҜ|вҲһ|ПҖ|В·', Number),
            #
            # Variables
            # =========
            (r'[a-z]' + _iwc + r'*', Name.Variable),
            #
            # 2-Modifiers
            # ===========
            # Needs to come before the 1-modifiers due to _рқ•Ј and _рқ•Ј_
            (r'[вҲҳв—ӢвҠёвҹңвҢҫвҠҳв—¶вҺүвҡҮвҚҹвҺҠ]', Name.Property),
            (r'_(рқ•Ј|[a-zA-Z0-9]+)_', Name.Property),
            #
            # 1-Modifiers
            # ===========
            (r'[ЛҷЛңЛҳВЁвҢңвҒјВҙЛқ`рқ•Ј]', Name.Attribute),
            (r'_(рқ•Ј|[a-zA-Z0-9]+)', Name.Attribute),
            #
            # Functions
            # =========
            # The monadic or dyadic function primitives and function
            # operands and arguments, along with function self-reference
            (r'[+\-Г—Г·\вӢҶвҲҡвҢҠвҢҲвҲ§вҲЁВ¬|вүӨ<>вүҘ=вү вүЎвүўвҠЈвҠўвҘҠвҲҫвүҚвӢҲвҶ‘вҶ“вҶ•В«В»вҢҪвҚү/вҚӢвҚ’вҠҸвҠ‘вҠҗвҠ’вҲҠвҚ·вҠ”!рқ•Һрқ•Ҹрқ”Ҫрқ”ҫрқ•Ҡ]',
             Operator),
            (r'[A-Z]' + _iwc + r'*|вҖў' + _iwc + r'+', Operator),
            #
            # Constant
            # ========
            (r'Лҷ', Name.Constant),
            #
            # Define/Export/Change
            # ====================
            (r'[вҶҗвҶ©вҮҗ]', Keyword.Declaration),
            #
            # Blocks
            # ======
            (r'[{}]', Keyword.Type),
            #
            # Extra characters
            # ================
            (r'[;:?рқ•Ёрқ•©рқ•—рқ•ҳрқ•Ө]', Name.Entity),
            #

        ],
    }
